refsection.programlisting:
slice = imresize(rgb2gray(imread(fullpath(getIPCVpath() + "/images/opencv_left01.jpg"))), [32 48]);
volume = cat(3, slice, slice, slice);
volume(:, :, 2) = volume(:, :, 2) * 0.6;
out = imadjust3(volume);
subplot(1, 2, 1);
imshow(volume(:, :, 2));
subplot(1, 2, 2);
imshow(out(:, :, 2));
